+// ============================================================================
+// Member Definition
+// ============================================================================
+
+/// Member definition (matches PyMemberDef)
+pub const PyMemberDef = struct {
+    name: []const u8,
+    type: MemberType,
+    offset: usize,
+    flags: i32 = 0,
+    doc: ?[]const u8 = null,
