+        .T_LONGLONG => @as(*align(1) i64, @ptrCast(ptr)).* = value.longlong_val,
+        .T_ULONGLONG => @as(*align(1) u64, @ptrCast(ptr)).* = value.ulonglong_val,
+        .T_PYSSIZET => @as(*align(1) isize, @ptrCast(ptr)).* = value.ssize_val,
